    26  /**
    27   * SCRAM Credential persistence utility functions. Implements format conversion used
    28   * for the credential store implemented in Kafka. Credentials are persisted as a comma-separated
    29   * String of key-value pairs:
    30   * <pre>
    31   *   salt=<i>salt</i>,stored_key=<i>stored_key</i>,server_key=<i>server_key</i>,iterations=<i>iterations</i>
    32   * </pre>
    33   *
    34   */
    35  public final class ScramCredentialUtils {
    36      private static final String SALT = "salt";
    37      private static final String STORED_KEY = "stored_key";
    38      private static final String SERVER_KEY = "server_key";
    39      private static final String ITERATIONS = "iterations";
    40
    41      private ScramCredentialUtils() {}
    42
    43      public static String credentialToString(ScramCredential credential) {
    44          return String.format("%s=%s,%s=%s,%s=%s,%s=%d",
    45                 SALT,
    46                 Base64.getEncoder().encodeToString(credential.salt()),
    47                 STORED_KEY,
    48                 Base64.getEncoder().encodeToString(credential.storedKey()),
    49                 SERVER_KEY,
    50                 Base64.getEncoder().encodeToString(credential.serverKey()),
    51                 ITERATIONS,
    52                 credential.iterations());
    53      }
    54
    55      public static ScramCredential credentialFromString(String str) {
    56          Properties props = toProps(str);
    57          if (props.size() != 4 || !props.containsKey(SALT) || !props.containsKey(STORED_KEY) ||
    58                  !props.containsKey(SERVER_KEY) || !props.containsKey(ITERATIONS)) {
    59              throw new IllegalArgumentException("Credentials not valid: " + str);
    60          }
    61          byte[] salt = Base64.getDecoder().decode(props.getProperty(SALT));
    62          byte[] storedKey = Base64.getDecoder().decode(props.getProperty(STORED_KEY));
    63          byte[] serverKey = Base64.getDecoder().decode(props.getProperty(SERVER_KEY));
    64          int iterations = Integer.parseInt(props.getProperty(ITERATIONS));
    65          return new ScramCredential(salt, storedKey, serverKey, iterations);
    66      }
    67
    68      private static Properties toProps(String str) {
    69          Properties props = new Properties();
    70          String[] tokens = str.split(",");
    71          for (String token : tokens) {
    72              int index = token.indexOf('=');
    73              if (index <= 0)
    74                  throw new IllegalArgumentException("Credentials not valid: " + str);
    75              props.put(token.substring(0, index), token.substring(index + 1));
    76          }
    77          return props;
    78      }
    79
    80      public static void createCache(CredentialCache cache, Collection<String> mechanisms) {
    81          for (String mechanism : ScramMechanism.mechanismNames()) {
    82              if (mechanisms.contains(mechanism))
    83                  cache.createCache(mechanism, ScramCredential.class);
    84          }
    85      }
    86  }

